'use client';

import { useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { ArrowLeft, TrendingUp } from 'lucide-react';
import Sidebar from '@/components/layout/Sidebar';
import RightPanel from '@/components/layout/RightPanel';
import MobileNav from '@/components/layout/MobileNav';
import ArticleFeed from '@/components/feed/ArticleFeed';
import { mockArticles } from '@/data/articles';

export default function TrendingPage() {
  const router = useRouter();

  const trending = useMemo(() => {
    return [...mockArticles].sort(
      (a, b) =>
        (b.likesCount + b.commentsCount * 2 + b.sharesCount) -
        (a.likesCount + a.commentsCount * 2 + a.sharesCount)
    );
  }, []);

  return (
    <div className="min-h-screen" style={{ background: '#000' }}>
      <Sidebar />
      <main className="lg:ml-[275px] xl:mr-[350px] min-h-screen border-r" style={{ borderColor: '#2F3336' }}>
        <div className="sticky top-0 z-30 flex items-center gap-4 px-4 py-3 border-b"
          style={{ background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(12px)', borderColor: '#2F3336' }}
        >
          <button onClick={() => router.back()} className="p-2 rounded-full hover:bg-white/10" style={{ color: '#E7E9EA' }}>
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <TrendingUp className="w-5 h-5" style={{ color: '#F97316' }} />
            <h1 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>Xu hướng</h1>
          </div>
        </div>

        <ArticleFeed articles={trending} />
      </main>
      <RightPanel />
      <MobileNav />
    </div>
  );
}
